<?php declare(strict_types=1); $cfg=require __DIR__.'/../config/config.php';$dir=$cfg['paths']['backups'];is_dir($dir)||mkdir($dir,0755,true);$file=$dir.'/backup-'.date('Ymd-His').'.zip';$zip=new ZipArchive();$zip->open($file,ZipArchive::CREATE);$zip->addFile(__DIR__.'/../sql/schema.sql','schema.sql');$zip->close();foreach(glob($dir.'/*.zip')?:[] as $f){if(filemtime($f)<time()-30*86400)unlink($f);}echo "Backup: $file\n";
